bash_commands.command:
python3 << 'EOF'
import requests

# Try additional Docker network ranges
for i in range(1, 30):
    url = f"http://172.17.0.{i}:3000"
    try:
        resp = requests.get(f"{url}/api/v1/info", timeout=1)
        if resp.status_code == 200:
            print(f"Found RocketChat at {url}: {resp.json()}")
    except:
        pass

# Also try port 80
for i in range(1, 30):
    url = f"http://172.17.0.{i}:80"
    try:
        resp = requests.get(url, timeout=1)
        if resp.status_code in [200, 301, 302]:
            print(f"HTTP service at {url}: status={resp.status_code}")
    except:
        pass
EOF

